mapper.select:
select app_id from im_app_usage
where user_id = #{userId}
order by usage_time desc
limit #{limit}

mapper.delete:
delete from im_app_usage
where user_id = #{userId}
and id not in (
    select id from (
        select id from im_app_usage
        where user_id = #{userId}
        order by usage_time desc
        limit #{keepCount}
    ) as tmp
)
